public void deleteMarked()
{

    if(ETGACFParameters::find().EnableAccrualSchemePostingMonthly)
    {
        LedgerJournalTrans                  ledgerJournalTransloc;
        FormDataSource                      ledgerJournalTrans_ds;
        ETGLedgerJournalTransAccrual        ledgerJournalTransAccrual;
        ETGLedgerJournalTransAccrualTrans   ledgerJournalTransAccrualTrans;

        ledgerJournalTrans_ds = this.formRun().dataSource(formDataSourceStr(LedgerJournalTransDaily, LedgerJournalTrans));

        for(ledgerJournalTransloc = ledgerJournalTrans_ds.getFirst(true) ? ledgerJournalTrans_ds.getFirst(true):ledgerJournalTrans_ds.cursor();
        ledgerJournalTransloc;
        ledgerJournalTransloc = ledgerJournalTrans_ds.getNext())
        {
            delete_from ledgerJournalTransAccrual
            where ledgerJournalTransAccrual.RefRecid == ledgerJournalTransloc.RecId
            && ledgerJournalTransAccrual.RefTableid == ledgerJournalTransloc.TableId;

            delete_from ledgerJournalTransAccrualTrans
            where ledgerJournalTransAccrualTrans.RefRecid == ledgerJournalTransloc.RecId
            && ledgerJournalTransAccrualTrans.RefTableid == ledgerJournalTransloc.TableId;
        }
    }
    next deleteMarked();
}
